import{C as e,I as t,K as n,L as r,N as i,R as a,X as o,d as s,i as c,q as l,x as u}from"../chunks/DI_erTYQ.js";import{c as d}from"../chunks/B7853-LL.js";import"../chunks/ibwe1TAv.js";import{t as f}from"../chunks/CVfHkc3z.js";var p=e(`<h1>Glossary</h1> <p>A quick, plain-English lookup for every technical word that appears in the tutorial. Use it whenever a term feels fuzzy — no shame in coming back here often.</p> <hr/> <h2>YAML core terms</h2> <p><strong>YAML</strong> — a plain-text format for storing configuration. Stands for “YAML Ain’t Markup Language”. <em>Lesson 1</em></p> <p><strong>Key</strong> — the label on the left of a colon. In <code>voltage: 1.2</code>, the key is <code>voltage</code>. <em>Lesson 2</em></p> <p><strong>Value</strong> — what’s on the right of a colon. In <code>voltage: 1.2</code>, the value is <code>1.2</code>. <em>Lesson 2</em></p> <p><strong>Key-value pair</strong> — a key together with its value, e.g. <code>frequency_mhz: 100</code>. The basic building block of YAML. <em>Lesson 2</em></p> <p><strong>Scalar</strong> — a single, simple value: text, a number, or true/false. Not a list or a group. <em>Lesson 2</em></p> <p><strong>String</strong> — a piece of text, usually wrapped in quotes: <code>"TitanCore"</code>. <em>Lesson 2</em></p> <p><strong>Integer</strong> — a whole number with no decimal point: <code>100</code>, <code>25</code>, <code>-7</code>. <em>Lesson 2</em></p> <p><strong>Float</strong> — a number with a decimal point: <code>1.2</code>, <code>3.14</code>. <em>Lesson 2</em></p> <p><strong>Boolean</strong> — a true/false value. YAML accepts <code>true</code> and <code>false</code> (lowercase). <em>Lesson 2</em></p> <p><strong>Comment</strong> — text starting with <code>#</code> that the computer ignores; only humans read it. <em>Lesson 2</em></p> <p><strong>Indentation</strong> — the spaces at the start of a line. YAML uses indentation to show grouping. Always <strong>spaces</strong>, never tabs. <em>Lesson 3</em></p> <p><strong>Nested</strong> — placed inside something else. A block of keys indented under a parent key is nested. <em>Lesson 3</em></p> <p><strong>List</strong> — an ordered series of items, each starting with a dash (<code>-</code>). <em>Lesson 4</em></p> <p><strong>Object</strong> — a group of related key-value pairs, e.g. one chip’s complete spec. Sometimes called a “dictionary” or “mapping”. <em>Lesson 4</em></p> <p><strong>Multi-line text</strong> — text that spans several lines. YAML uses <code>|</code> to keep line breaks and <code>&gt;</code> to fold them into one line. <em>Lesson 5</em></p> <p><strong>Block style</strong> — the readable, multi-line YAML format that uses indentation. Opposite of flow style. <em>Lesson 5</em></p> <p><strong>Flow style</strong> — the compact one-line YAML format using <code>[…]</code> and <code>&#123;…&#125;</code>. Valid but harder to read. <em>Lesson 12</em></p> <p><strong>Anchor</strong> — a named template marker. Created with <code>&name</code>. <em>Lesson 9</em></p> <p><strong>Alias</strong> — a reference back to an anchor. Written as <code>*name</code>. <em>Lesson 9</em></p> <p><strong>Merge key</strong> — <code>&lt;&lt;:</code> followed by an alias. Copies all key-value pairs from the anchored block into the current block. <em>Lesson 9</em></p> <hr/> <h2>Errors and validation</h2> <p><strong>Syntax</strong> — the rules for how a language must be written. A “syntax error” means you broke one of those rules. <em>Lesson 7</em></p> <p><strong>Validate / validation</strong> — check whether a file follows the rules. A YAML validator tells you if your file is well-formed. <em>Lesson 8</em></p> <p><strong>Parse</strong> — read a file and turn it into a structure the computer can use. <code>yaml.safe_load()</code> parses YAML. <em>Lesson 12</em></p> <p><strong>Duplicate key</strong> — using the same key twice at the same level. The second one silently overwrites the first — a common bug. <em>Lesson 7</em></p> <hr/> <h2>Coding terms (Part 4)</h2> <p><strong>Script</strong> — a plain text file with instructions for the computer (e.g. <code>run_synth.py</code>). You can open it in any editor. <em>Lesson 11</em></p> <p><strong>Terminal</strong> (also: shell, command line, console) — the text window where you type commands. Same idea as Cadence’s Tcl prompt. <em>Lesson 11</em></p> <p><strong>File path</strong> — the address of a file on disk. Relative: <code>chip.yaml</code>. Absolute: <code>/home/alice/chip.yaml</code>. <em>Lesson 11</em></p> <p><strong>Library</strong> — reusable code somebody else wrote. Python’s <code>yaml</code> library reads and writes YAML files for you. <em>Lesson 11</em></p> <p><strong><code>pip</code></strong> — Python’s package installer. <code>pip install pyyaml</code> downloads the YAML library. <em>Lesson 11</em></p> <p><strong><code>import</code></strong> — Python keyword that loads a library. <code>import yaml</code> makes the YAML library available in the script. <em>Lesson 11</em></p> <p><strong>Function</strong> — a named piece of code you can call to do a task. <code>yaml.safe_load(f)</code> calls the <code>safe_load</code> function with <code>f</code> as input. <em>Lesson 12</em></p> <p><strong>Argument</strong> — a value you pass into a function. In <code>yaml.dump(data, f)</code>, <code>data</code> and <code>f</code> are arguments. <em>Lesson 13</em></p> <p><strong>Dictionary (dict)</strong> — Python’s name for a collection of key-value pairs. When Python reads a YAML file, the result is a dictionary. <em>Lesson 12</em></p> <p><strong>Index</strong> — a number that picks an item from a list. Lists start at 0 — <code>team[0]</code> is the first item, <code>team[1]</code> is the second. <em>Lesson 12</em></p> <p><strong>Exception / error</strong> — when something goes wrong, Python raises an exception that stops the program. <code>YAMLError</code> and <code>FileNotFoundError</code> are examples. <em>Lesson 14</em></p> <p><strong><code>try / except</code></strong> — Python’s way of handling exceptions gracefully instead of crashing. <em>Lesson 14</em></p> <hr/> <h2>Hardware / EDA terms (used as analogies)</h2> <p><strong>SDC</strong> — Synopsys Design Constraints. A text file telling synthesis tools about clocks and timing. Conceptually similar to a YAML config — both feed parameters into a tool.</p> <p><strong>Liberty (<code>.lib</code>)</strong> — a text file describing standard cell timing/power. Like YAML, it’s plain text packed with key-value-style information.</p> <p><strong>Verilog/VHDL</strong> — hardware description languages. Many design teams generate per-block Verilog parameters from a central YAML config.</p> <p><strong>Testbench</strong> — verification code that exercises a design. Often configured by YAML files specifying which tests to run and with what parameters.</p> <p><strong>EDA tool</strong> — Electronic Design Automation tool (Cadence, Synopsys, Mentor). They typically read configs (YAML, Tcl, SDC) and produce reports.</p> <hr/> <!> <div class="not-prose" style="margin-top:2rem;display:flex;justify-content:center;"><a style="display:inline-flex;align-items:center;gap:0.5rem;padding:0.65rem 1.25rem;border-radius:8px;font-weight:600;font-size:0.85rem;text-decoration:none;background:var(--color-accent);color:white;font-family:var(--font-ui);transition:all 0.25s ease;">← Back to Home</a></div>`,1);function m(e,m){l(m,!0),c(()=>{let e=e=>e.toLowerCase().replace(/[^a-z0-9]+/g,`-`).replace(/^-|-$/g,``);if(document.querySelectorAll(`#lesson-content p > strong:first-child`).forEach(t=>{let n=t.parentElement;n&&!n.id&&(n.id=e(t.textContent||``))}),location.hash){let e=document.getElementById(decodeURIComponent(location.hash.slice(1)));e&&e.scrollIntoView({behavior:`smooth`,block:`start`})}});var h=p(),g=a(r(h),104);f(g,{});var _=a(g,2),v=t(_);o(_),i(()=>s(v,`href`,`${d??``}/`)),u(e,h),n()}export{m as component};